/**
 * @name Script engine eval with user-controlled input
 * @description User-controlled data flows to ScriptEngine.eval(), enabling code injection
 * @kind path-problem
 * @problem.severity error
 * @id java/script-engine-injection
 * @tags security
 *       external/cwe/cwe-094
 *       external/cwe/cwe-095
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScriptEngineConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.script", "ScriptEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ScriptEngineFlow = TaintTracking::Global<ScriptEngineConfig>;
import ScriptEngineFlow::PathGraph

from ScriptEngineFlow::PathNode source, ScriptEngineFlow::PathNode sink
where ScriptEngineFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script engine eval with data from $@.", source.getNode(), "user input"

