/**
 * @name User input flows to SwitchTaskUtils.evaluate via HTTP API
 * @description Trace user-controlled switch condition from HTTP API to ScriptEngine.eval()
 * @kind path-problem
 * @problem.severity error
 * @id java/switch-task-code-injection-path
 * @tags security
 *       external/cwe/cwe-094
 *       external/cwe/cwe-095
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SwitchInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: argument to SwitchTaskUtils.evaluate()
    exists(MethodCall mc |
      mc.getMethod().hasName("evaluate") and
      mc.getMethod().getDeclaringType().getName() = "SwitchTaskUtils" and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Also sink: direct ScriptEngine.eval() call
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.script", "ScriptEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module SwitchInjectionFlow = TaintTracking::Global<SwitchInjectionConfig>;
import SwitchInjectionFlow::PathGraph

from SwitchInjectionFlow::PathNode source, SwitchInjectionFlow::PathNode sink
where SwitchInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Code injection: user data flows to script evaluation from $@.", source.getNode(), "user input"

/**
 * @name SnakeYAML load with user-controlled data
 * @description User-controlled data flows to SnakeYAML Yaml.load(), enabling arbitrary object instantiation
 * @kind path-problem
 * @problem.severity error
 * @id java/snakeyaml-deserialization
 * @tags security
 *       external/cwe/cwe-502
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SnakeYAMLConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("load") or mc.getMethod().hasName("loadAll")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.yaml.snakeyaml", "Yaml") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module SnakeYAMLFlow = TaintTracking::Global<SnakeYAMLConfig>;
import SnakeYAMLFlow::PathGraph

from SnakeYAMLFlow::PathNode source, SnakeYAMLFlow::PathNode sink
where SnakeYAMLFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "SnakeYAML deserialization with data from $@.", source.getNode(), "user input"
